import { ChangeEvent, Dispatch, memo, SetStateAction, useState, useCallback } from 'react'
import { useDispatch, useSelector } from 'react-redux'
import { RoomRenovationParams } from 'api/model/property/communitys/roomRenovationModel'
import { find } from 'modules/property/communitys/roomRenovation'
import { Box, FormControl, Button, Stack, TextField, MenuItem } from '@mui/material'
import { Delete, History, Search } from '@mui/icons-material'
import { buttonStyles } from 'components/DeleteModal'
import message from 'components/Message'

const textFieldStyles = {
  '& .MuiOutlinedInput-root': {
    '& fieldset': {
      border: 'none'
    },
    '&:hover fieldset': {
      border: '1px solid',
      borderColor: 'primary.main'
    },
    '&.Mui-focused fieldset': {
      border: '2px solid',
      borderColor: 'primary.main'
    }
  }
}

interface SearchFormProps {
  selectedRows: Set<string | undefined>
  setDelOpen: Dispatch<SetStateAction<boolean>>
}

const FormSearch: React.FC<SearchFormProps> = ({ selectedRows, setDelOpen }) => {
  const dispatch = useDispatch<AppDispatch>()
  const { page } = useSelector((state: RootState) => state.RoomRenovationSlice)

  const [searchParams, setSearchParams] = useState<RoomRenovationParams>({
    roomName: '',
    personName: '',
    personTel: '',
    status: '',
    isPostpone: 0,
    createdAt: '',
    startTime: '',
    endTime: ''
  })

  const handleInputChange =
    (field: keyof RoomRenovationParams) => (event: ChangeEvent<HTMLInputElement>) => {
      setSearchParams(prevData => ({
        ...prevData,
        [field]: event.target.value
      }))
    }

  const fetchData = useCallback(
    async (params: RoomRenovationParams & PaginationParams) => {
      const closeLoading = message.loading('正在加载列表中，请稍后...')
      try {
        const res = await dispatch(
          find({ 'page.num': page.num, 'page.size': page.size, ...params })
        )
        if ('error' in res && res.error?.message) {
          throw new Error(res.error.message)
        }
      } catch (err: unknown) {
        closeLoading()
        if (err instanceof Error) message.error(err.message)
      } finally {
        closeLoading()
      }
    },
    [dispatch, page.num, page.size]
  )

  const handleSearch = () => {
    fetchData(searchParams)
  }

  return (
    <Box>
      <Stack direction="row" spacing={3} component="form" sx={{ mb: 1.5 }}>
        <FormControl sx={{ width: { xs: '100%', md: '25ch' } }} variant="outlined">
          <TextField
            size="small"
            label="请输入房屋编号楼栋-单元-房屋"
            type="text"
            variant="outlined"
            sx={textFieldStyles}
            value={searchParams.roomName}
            onChange={handleInputChange('roomName')}
          />
        </FormControl>
        <FormControl sx={{ width: { xs: '100%', md: '25ch' } }} variant="outlined">
          <TextField
            size="small"
            label="请输入联系人"
            type="text"
            variant="outlined"
            sx={textFieldStyles}
            value={searchParams.personName}
            onChange={handleInputChange('personName')}
          />
        </FormControl>
        <FormControl sx={{ width: { xs: '100%', md: '25ch' } }} variant="outlined">
          <TextField
            size="small"
            label="请输入联系电话"
            type="text"
            variant="outlined"
            sx={textFieldStyles}
            value={searchParams.personTel}
            onChange={handleInputChange('personTel')}
          />
        </FormControl>
        <FormControl sx={{ width: { xs: '100%', md: '25ch' } }} variant="outlined">
          <TextField
            select
            size="small"
            label="请选择状态"
            value={searchParams.status || ''}
            onChange={handleInputChange('status')}
            variant="outlined"
            sx={textFieldStyles}
          >
            {[
              { value: '1000', label: '待审核' },
              { value: '2000', label: '审核不通过' },
              { value: '3000', label: '装修中' },
              { value: '4000', label: '待验收' },
              { value: '5000', label: '验收成功' },
              { value: '6000', label: '验收失败' }
            ].map(option => (
              <MenuItem key={option.value} value={option.value}>
                {option.label}
              </MenuItem>
            ))}
          </TextField>
        </FormControl>
        <FormControl sx={{ width: { xs: '100%', md: '25ch' } }} variant="outlined">
          <TextField
            select
            size="small"
            label="请选择是否延期"
            value={searchParams.isPostpone}
            onChange={handleInputChange('isPostpone')}
            variant="outlined"
            sx={textFieldStyles}
          >
            {[
              { value: 0, label: '正常' },
              { value: 1, label: '延期' }
            ].map(option => (
              <MenuItem key={option.value} value={option.value}>
                {option.label}
              </MenuItem>
            ))}
          </TextField>
        </FormControl>
      </Stack>
      <Stack direction="row" spacing={3} component="form" sx={{ mb: 1.5 }}>
        {/* <FormControl sx={{ width: { xs: '100%', md: '25ch' } }} variant="outlined">
          <TextField
            size="small"
            label="请输入装修时间"
            type="date"
            variant="outlined"
            sx={textFieldStyles}
            value={searchParams.createdAt}
            onChange={handleInputChange('createdAt')}
            slotProps={{
              inputLabel: {
                shrink: true
              }
            }}
          />
        </FormControl> */}
        <FormControl sx={{ width: { xs: '100%', md: '25ch' } }} variant="outlined">
          <TextField
            size="small"
            label="请输入申请开始时间"
            type="date"
            variant="outlined"
            sx={textFieldStyles}
            value={searchParams.startTime}
            onChange={handleInputChange('startTime')}
            slotProps={{
              inputLabel: {
                shrink: true
              }
            }}
          />
        </FormControl>
        <FormControl sx={{ width: { xs: '100%', md: '25ch' } }} variant="outlined">
          <TextField
            size="small"
            label="请输入申请结束时间"
            type="date"
            variant="outlined"
            sx={textFieldStyles}
            value={searchParams.endTime}
            onChange={handleInputChange('endTime')}
            slotProps={{
              inputLabel: {
                shrink: true
              }
            }}
          />
        </FormControl>
      </Stack>
      <Stack direction="row" spacing={1} sx={{ mb: 2 }}>
        <Button
          size="small"
          variant="contained"
          color="error"
          startIcon={<Search />}
          sx={buttonStyles('#2660ad', '#1d428a')}
          onClick={handleSearch}
        >
          查询
        </Button>
        <Button
          size="small"
          variant="contained"
          color="error"
          startIcon={<History />}
          sx={buttonStyles('darkgray', '#696969')}
          onClick={() => {
            setSearchParams({
              roomName: '',
              personName: '',
              personTel: '',
              status: '',
              isPostpone: 0,
              createdAt: '',
              startTime: '',
              endTime: ''
            })
            fetchData({
              roomName: '',
              personName: '',
              personTel: '',
              status: '',
              isPostpone: 0,
              createdAt: '',
              startTime: '',
              endTime: '',
              'page.num': page.num,
              'page.size': page.size
            })
          }}
        >
          重置
        </Button>
        <Button
          size="small"
          variant="contained"
          color="error"
          startIcon={<Delete />}
          sx={buttonStyles('#B22222', '#8B0000')}
          onClick={() => {
            if (![...selectedRows].length) {
              return message.warning('请选择至少一项')
            }
            setDelOpen(true)
          }}
        >
          批量删除
        </Button>
      </Stack>
    </Box>
  )
}

export default memo(FormSearch)
